final class DeviceIntegrityManager {
    static let shared = DeviceIntegrityManager()
    
    private init() {}
    
    struct IntegrityReport {
        let isJailbroken: Bool
        let isDebuggerAttached: Bool
        let isRunningInEmulator: Bool
        let hasBeenTampered: Bool
        let isTrustworthy: Bool
        
        var overallTrust: Bool {
            return isTrustworthy && !isJailbroken && !isDebuggerAttached && !isRunningInEmulator && !hasBeenTampered
        }
    }
    
    func performIntegrityCheck() -> IntegrityReport {
        let jailbroken = checkJailbreak()
        let debugger = checkDebugger()
        let emulator = checkEmulator()
        let tampered = checkTampering()
        let trustworthy = !jailbroken && !debugger && !emulator && !tampered
        
        return IntegrityReport(
            isJailbroken: jailbroken,
            isDebuggerAttached: debugger,
            isRunningInEmulator: emulator,
            hasBeenTampered: tampered,
            isTrustworthy: trustworthy
        )
    }
    
    private func checkJailbreak() -> Bool {
        // Check for common jailbreak files
        let jailbreakPaths = [
            "/Applications/Cydia.app",
            "/Applications/Sileo.app",
            "/Library/MobileSubstrate/MobileSubstrate.dylib",
            "/bin/bash",
            "/usr/sbin/sshd",
            "/etc/apt",
            "/private/var/lib/apt/",
            "/usr/bin/ssh",
            "/private/var/lib/cydia",
            "/private/var/stash",
            "/private/var/tmp/cydia.log",
            "/usr/libexec/sftp-server",
            "/usr/lib/TweakInject",
            "/var/binpack",
            "/Library/PreferenceBundles/SubstituteSettings.bundle"
        ]
        
        for path in jailbreakPaths {
            if FileManager.default.fileExists(atPath: path) {
                return true
            }
        }
        
        // Check if app can write to system directories
        let testPath = "/private/jailbreak_test_\(UUID().uuidString)"
        do {
            try "test".write(toFile: testPath, atomically: true, encoding: .utf8)
            try FileManager.default.removeItem(atPath: testPath)
            return true
        } catch {
            // Expected behavior on non-jailbroken device
        }
        
        // Check for suspicious URL schemes
        if let url = URL(string: "cydia://package/com.example.package") {
            if UIApplication.shared.canOpenURL(url) {
                return true
            }
        }
        
        // Check for suspicious dylibs
        let suspiciousDylibs = ["SubstrateLoader", "SSLKillSwitch", "MobileSubstrate", "TweakInject", "CydiaSubstrate"]
        let imageCount = _dyld_image_count()
        for i in 0..<imageCount {
            if let imageName = _dyld_get_image_name(i) {
                let name = String(cString: imageName)
                for dylib in suspiciousDylibs {
                    if name.lowercased().contains(dylib.lowercased()) {
                        return true
                    }
                }
            }
        }
        
        // Check if sandbox is intact
        let sandboxCheck = fork()
        if sandboxCheck >= 0 {
            // fork() should fail on non-jailbroken devices
            return true
        }
        
        return false
    }
    
    private func checkDebugger() -> Bool {
        var info = kinfo_proc()
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, getpid()]
        var size = MemoryLayout<kinfo_proc>.stride
        
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        if result == 0 {
            return (info.kp_proc.p_flag & P_TRACED) != 0
        }
        
        return false
    }
    
    private func checkEmulator() -> Bool {
        #if targetEnvironment(simulator)
        return true
        #else
        // Check for simulator-specific environment variables
        if ProcessInfo.processInfo.environment["SIMULATOR_DEVICE_NAME"] != nil {
            return true
        }
        
        // Check hardware model
        var systemInfo = utsname()
        uname(&systemInfo)
        let machine = withUnsafePointer(to: &systemInfo.machine) {
            $0.withMemoryRebound(to: CChar.self, capacity: 1) {
                String(cString: $0)
            }
        }
        
        if machine.contains("x86") || machine.contains("i386") {
            return true
        }
        
        return false
