        let mobileprovisionPath = bundlePath.appendingPathComponent("embedded.mobileprovision")
        
        #if !DEBUG
        if !FileManager.default.fileExists(atPath: mobileprovisionPath) {
            return true
        }
        #endif
        
        // Check bundle identifier integrity
        guard let bundleId = Bundle.main.bundleIdentifier else { return true }
        let expectedBundleId = "com.tradingapp.finance"
        if bundleId != expectedBundleId {
            return true
        }
        
        // Verify Info.plist hasn't been modified
        guard let infoPlistPath = Bundle.main.path(forResource: "Info", ofType: "plist"),
              let infoPlistData = FileManager.default.contents(atPath: infoPlistPath) else {
            return false
        }
        
        let hash = SHA256.hash(data: infoPlistData)
        let _ = hash.compactMap { String(format: "%02x", $0) }.joined()
        
        return false
    }
