// MARK: - Secure Network Manager with Certificate Pinning

final class SecureNetworkManager {
    static let shared = SecureNetworkManager()
    
    private let session: URLSession
    private let pinnedCertificateHashes: Set<String> = [
        "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB=" // Replace with actual cert hash
    ]
    
    private let baseURL = "https://api.tradingplatform.com/v1"
    
    private init() {
        let config = URLSessionConfiguration.ephemeral
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        config.timeoutIntervalForRequest = 30
        config.timeoutIntervalForResource = 60
        
        let delegate = SSLPinningDelegate()
        session = URLSession(configuration: config, delegate: delegate, delegateQueue: nil)
    }
    
    func authenticatedRequest(
        endpoint: String,
        method: String = "GET",
        body: [String: Any]? = nil,
        completion: @escaping (Result<Data, NetworkError>) -> Void
    ) {
        // Check device integrity before any API call
        let integrity = DeviceIntegrityManager.shared.performIntegrityCheck()
        guard integrity.overallTrust else {
            completion(.failure(.untrustedDevice))
            return
        }
        
        guard let token = SecureStorageManager.shared.retrieveAPIToken() else {
            completion(.failure(.unauthorized))
            return
        }
        
        guard let url = URL(string: "\(baseURL)/\(endpoint)") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method
        request.setValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        
        // Add request signing
        let timestamp = String(Int(Date().timeIntervalSince1970))
        request.setValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        
        let nonce = UUID().uuidString
        request.setValue(nonce, forHTTPHeaderField: "X-Nonce")
        
        if let body = body {
            do {
                let jsonData = try JSONSerialization.data(withJSONObject: body)
                request.httpBody = jsonData
                
                // Sign the request
                let signature = signRequest(data: jsonData, timestamp: timestamp, nonce: nonce)
                request.setValue(signature, forHTTPHeaderField: "X-Signature")
            } catch {
                completion(.failure(.encodingError))
                return
            }
        }
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.networkError(error)))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(.invalidResponse))
                return
            }
            
            switch httpResponse.statusCode {
            case 200...299:
                guard let data = data else {
                    completion(.failure(.noData))
                    return
                }
                completion(.success(data))
            case 401:
                completion(.failure(.unauthorized))
            case 403:
                completion(.failure(.forbidden))
            case 429:
                completion(.failure(.rateLimited))
            default:
                completion(.failure(.serverError(httpResponse.statusCode)))
            }
        }.resume()
    }
    
    private func signRequest(data: Data, timestamp: String, nonce: String) -> String {
        let signingKey = SymmetricKey(size: .bits256)
        let payload = data + timestamp.data(using: .utf8)! + nonce.data(using: .utf8)!
        let signature = HMAC<SHA256>.authenticationCode(for: payload, using: signingKey)
        return Data(signature).base64EncodedString()
    }
    
    enum NetworkError: Error, LocalizedError {
        case untrustedDevice
        case unauthorized
        case forbidden
        case invalidURL
        case encodingError
        case networkError(Error)
        case invalidResponse
        case noData
        case rateLimited
        case serverError(Int)
        case decodingError
        
        var errorDescription: String? {
            switch self {
            case .untrustedDevice: return "Device integrity check failed. Trading is disabled."
            case .unauthorized: return "Authentication required. Please log in again."
            case .forbidden: return "Access denied."
            case .invalidURL: return "Invalid request."
            case .encodingError: return "Failed to encode request."
            case .networkError(let error): return "Network error: \(error.localizedDescription)"
            case .invalidResponse: return "Invalid server response."
            case .noData: return "No data received."
            case .rateLimited: return "Too many requests. Please wait."
            case .serverError(let code): return "Server error (\(code))."
            case .decodingError: return "Failed to decode response."
            }
        }
    }
}

// MARK: - SSL Pinning Delegate

final class SSLPinningDelegate: NSObject, URLSessionDelegate {
    
    private let pinnedPublicKeyHashes: [String] = [
        // SHA256 hashes of the public keys of your server certificates
        "sha256/AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA="
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Evaluate server trust
        var error: CFError?
        let isValid = SecTrustEvaluateWithError(serverTrust, &error)
        
        guard isValid else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Verify certificate chain
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        guard certificateCount > 0 else {
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Extract and verify public key hash
        if let serverCertificate = SecTrustCopyCertificateChain(serverTrust) as? [SecCertificate],
           let certificate = serverCertificate.first {
            let serverPublicKey = SecCertificateCopyKey(certificate)
            if let serverPublicKeyData = serverPublicKey.flatMap({ SecKeyCopyExternalRepresentation($0, nil) as Data? }) {
                let hash = SHA256.hash(data: serverPublicKeyData)
                let hashString = "sha256/" + Data(hash).base64EncodedString()
                
                if pinnedPublicKeyHashes.contains(hashString) {
                    completionHandler(.useCredential, URLCredential(trust: serverTrust))
                    return
                }
            }
        }
        
        completionHandler(.cancelAuthenticationChallenge, nil)
    }
}

// MARK: - Data Models

struct Stock: Codable, Identifiable {
    let id: String
    let symbol: String
    let name: String
    let exchange: String
    var currentPrice: Decimal
    var previousClose: Decimal
    var dayHigh: Decimal
    var dayLow: Decimal
    var volume: Int64
    var lastUpdated: Date
    
    var priceChange: Decimal {
        return currentPrice - previousClose
    }
    
    var priceChangePercent: Decimal {
        guard previousClose != 0 else { return 0 }
        return (priceChange / previousClose) * 100
    }
    
    var isPositive: Bool {
        return priceChange >= 0
    }
}

enum OrderType: String, Codable, CaseIterable {
    case market = "MARKET"
    case limit = "LIMIT"
    case stopLoss = "STOP_LOSS"
    case stopLimit = "STOP_LIMIT"
    case trailingStop = "TRAILING_STOP"
    
    var displayName: String {
        switch self {
        case .market: return "Market"
        case .limit: return "Limit"
        case .stopLoss: return "Stop Loss"
        case .stopLimit: return "Stop Limit"
        case .trailingStop: return "Trailing Stop"
        }
    }
}

enum OrderSide: String, Codable {
    case buy = "BUY"
    case sell = "SELL"
}

enum OrderStatus: String, Codable {
    case pending = "PENDING"
    case submitted = "SUBMITTED"
    case partiallyFilled = "PARTIALLY_FILLED"
    case filled = "FILLED"
    case cancelled = "CANCELLED"
    case rejected = "REJECTED"
    case expired = "EXPIRED"
    
    var displayName: String {
        switch self {
        case .pending: return "Pending"
        case .submitted: return "Submitted"
        case .partiallyFilled: return "Partially Filled"
        case .filled: return "Filled"
        case .cancelled: return "Cancelled"
        case .rejected: return "Rejected"
        case .expired: return "Expired"
        }
    }
    
    var color: UIColor {
        switch self {
        case .filled: return .systemGreen
        case .pending, .submitted: return .systemOrange
        case .partiallyFilled: return .systemBlue
        case .cancelled, .expired: return .systemGray
        case .rejected: return .systemRed
        }
    }
}

enum TimeInForce: String, Codable, CaseIterable {
    case day = "DAY"
    case gtc = "GTC" // Good Till Cancelled
    case ioc = "IOC" // Immediate or Cancel
    case fok = "FOK" // Fill or Kill
    
    var displayName: String {
        switch self {
        case .day: return "Day"
        case .gtc: return "Good Till Cancelled"
        case .ioc: return "Immediate or Cancel"
        case .fok: return "Fill or Kill"
        }
    }
}

struct TradeOrder: Codable, Identifiable {
    let id: String
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantity: Decimal
    var filledQuantity: Decimal
    var limitPrice: Decimal?
    var stopPrice: Decimal?
    var trailingPercent: Decimal?
    let timeInForce: TimeInForce
    var status: OrderStatus
    var averageFilledPrice: Decimal?
    let createdAt: Date
    var updatedAt: Date
    var commission: Decimal?
    
    var totalValue: Decimal {
        let price = averageFilledPrice ?? limitPrice ?? 0
        return filledQuantity * price
    }
    
    var remainingQuantity: Decimal {
        return quantity - filledQuantity
    }
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let stockName: String
    var quantity: Decimal
    var averageCost: Decimal
    var currentPrice: Decimal
    var lastUpdated: Date
    
    var marketValue: Decimal {
        return quantity * currentPrice
    }
    
    var totalCost: Decimal {
        return quantity * averageCost
    }
    
    var unrealizedPnL: Decimal {
        return marketValue - totalCost
    }
    
    var unrealizedPnLPercent: Decimal {
        guard totalCost != 0 else { return 0 }
        return (unrealizedPnL / totalCost) * 100
    }
    
    var isProfit: Bool {
        return unrealizedPnL >= 0
    }
}

struct Portfolio: Codable {
    var cashBalance: Decimal
    var positions: [Position]
    var totalEquity: Decimal
    var dayPnL: Decimal
    var dayPnLPercent: Decimal
    var totalPnL: Decimal
    var totalPnLPercent: Decimal
    var buyingPower: Decimal
    var marginUsed: Decimal
    var lastUpdated: Date
    
    var totalMarketValue: Decimal {
        return positions.reduce(0) { $0 + $1.marketValue }
    }
    
    var positionCount: Int {
        return positions.count
    }
}

struct TradeConfirmation {
    let order: TradeOrder
    let estimatedCost: Decimal
    let estimatedCommission: Decimal
    let estimatedTotal: Decimal
    let warnings: [String]
}

// MARK: - Trading Engine

final class TradingEngine {
    static let shared = TradingEngine()
    
    private let networkManager = SecureNetworkManager.shared
    private let integrityManager = DeviceIntegrityManager.shared
    private let biometricAuth = BiometricAuthManager.shared
    
    private var portfolio: Portfolio?
    private var activeOrders: [TradeOrder] = []
    private var orderHistory: [TradeOrder] = []
    
    private let tradingQueue = DispatchQueue(label: "com.tradingapp.engine", qos: .userInitiated)
    private let portfolioLock = NSLock()
    
    // Risk management parameters
    private let maxOrderValue: Decimal = 100_000
    private let maxDailyTrades: Int = 100
    private let maxPositionConcentration: Decimal = 0.25 // 25% of portfolio
    private var dailyTradeCount: Int = 0
    private var lastTradeDate: Date?
    
    private init() {}
    
    // MARK: - Portfolio Management
    
    func loadPortfolio(completion: @escaping (Result<Portfolio, Error>) -> Void) {
        networkManager.authenticatedRequest(endpoint: "portfolio") { [weak self] result in
            switch result {
            case .success(let data):
                do {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    let portfolio = try decoder.decode(Portfolio.self, from: data)
                    self?.portfolioLock.lock()
                    self?.portfolio = portfolio
                    self?.portfolioLock.unlock()
                    completion(.success(portfolio))
                } catch {
                    completion(.failure(SecureNetworkManager.NetworkError.decodingError))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getPositions(completion: @escaping (Result<[Position], Error>) -> Void) {
        networkManager.authenticatedRequest(endpoint: "positions") { result in
            switch result {
            case .success(let data):
                do {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    let positions = try decoder.decode([Position].self, from: data)
                    completion(.success(positions))
                } catch {
                    completion(.failure(SecureNetworkManager.NetworkError.decodingError))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Trade Execution
    
    func previewOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal? = nil,
        stopPrice: Decimal? = nil,
        timeInForce: TimeInForce = .day,
        completion: @escaping (Result<TradeConfirmation, TradingError>) -> Void
    ) {
        tradingQueue.async { [weak self] in
            guard let self = self else { return }
            
            // Validate order parameters
            let validationResult = self.validateOrder(
                symbol: symbol,
                side: side,
                type: type,
                quantity: quantity,
                limitPrice: limitPrice,
                stopPrice: stopPrice
            )
            
            switch validationResult {
            case .failure(let error):
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            case .success:
                break
            }
            
            // Create preview order
            let order = TradeOrder(
                id: UUID().uuidString,
                symbol: symbol,
                side: side,
                type: type,
                quantity: quantity,
                filledQuantity: 0,
                limitPrice: limitPrice,
                stopPrice: stopPrice,
                trailingPercent: nil,
                timeInForce: timeInForce,
                status: .pending,
                averageFilledPrice: nil,
                createdAt: Date(),
                updatedAt: Date(),
                commission: nil
            )
            
            let estimatedPrice = limitPrice ?? self.portfolio?.positions.first(where: { $0.symbol == symbol })?.currentPrice ?? 0
            let estimatedCost = quantity * estimatedPrice
            let estimatedCommission: Decimal = 0 // Commission-free trading
            let estimatedTotal = side == .buy ? estimatedCost + estimatedCommission : estimatedCost - estimatedCommission
            
            var warnings: [String] = []
            
            // Check concentration risk
            if let portfolio = self.portfolio {
                let positionValue = estimatedCost
                let portfolioValue = portfolio.totalEquity
                if portfolioValue > 0 && (positionValue / portfolioValue) > self.maxPositionConcentration {
                    warnings.append("This order would result in a concentrated position (>\(self.maxPositionConcentration * 100)% of portfolio)")
                }
                
                if side == .buy && estimatedTotal > portfolio.buyingPower {
                    DispatchQueue.main.async {
                        completion(.failure(.insufficientFunds))
                    }
                    return
                }
            }
            
            if type == .market {
                warnings.append("Market orders execute at the best available price, which may differ from the last quoted price.")
            }
            
            let confirmation = TradeConfirmation(
                order: order,
                estimatedCost: estimatedCost,
                estimatedCommission: estimatedCommission,
                estimatedTotal: estimatedTotal,
                warnings: warnings
            )
            
            DispatchQueue.main.async {
                completion(.success(confirmation))
            }
        }
    }
    
    func executeOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal? = nil,
        stopPrice: Decimal? = nil,
        trailingPercent: Decimal? = nil,
        timeInForce: TimeInForce = .day,
        requireBiometric: Bool = true,
        completion: @escaping (Result<TradeOrder, TradingError>) -> Void
    ) {
        // Step 1: Device integrity check
        let integrity = integrityManager.performIntegrityCheck()
        guard integrity.overallTrust else {
            completion(.failure(.untrustedDevice))
            return
        }
        
        // Step 2: Biometric authentication for trade execution
        if requireBiometric {
            biometricAuth.authenticateForTrading { [weak self] success, error in
                guard success else {
                    completion(.failure(.authenticationFailed))
                    return
                }
                self?.performTradeExecution(
                    symbol: symbol,
                    side: side,
                    type: type,
                    quantity: quantity,
                    limitPrice: limitPrice,
                    stopPrice: stopPrice,
                    trailingPercent: trailingPercent,
                    timeInForce: timeInForce,
                    completion: completion
                )
            }
        } else {
            performTradeExecution(
                symbol: symbol,
                side: side,
                type: type,
                quantity: quantity,
                limitPrice: limitPrice,
                stopPrice: stopPrice,
                trailingPercent: trailingPercent,
                timeInForce: timeInForce,
                completion: completion
            )
        }
    }
    
    private func performTradeExecution(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal?,
        stopPrice: Decimal?,
        trailingPercent: Decimal?,
        timeInForce: TimeInForce,
        completion: @escaping (Result<TradeOrder, TradingError>) -> Void
    ) {
        tradingQueue.async { [weak self] in
            guard let self = self else { return }
            
            // Validate order
            let validationResult = self.validateOrder(
                symbol: symbol,
                side: side,
                type: type,
                quantity: quantity,
                limitPrice: limitPrice,
                stopPrice: stopPrice
            )
            
            switch validationResult {
            case .failure(let error):
                DispatchQueue.main.async { completion(.failure(error)) }
                return
            case .success:
                break
            }
            
            // Build order payload
            var orderPayload: [String: Any] = [
                "symbol": symbol,
                "side": side.rawValue,
                "type": type.rawValue,
                "quantity": "\(quantity)",
                "time_in_force": timeInForce.rawValue,
                "client_order_id": UUID().uuidString,
                "device_integrity_token": self.generateIntegrityToken()
            ]
            
            if let limitPrice = limitPrice {
                orderPayload["limit_price"] = "\(limitPrice)"
            }
            if let stopPrice = stopPrice {
                orderPayload["stop_price"] = "\(stopPrice)"
            }
            if let trailingPercent = trailingPercent {
                orderPayload["trailing_percent"] = "\(trailingPercent)"
            }
            
            // Submit order to API
            self.networkManager.authenticatedRequest(
                endpoint: "orders",
                method: "POST",
                body: orderPayload
            ) { [weak self] result in
                switch result {
                case .success(let data):
                    do {
                        let decoder = JSONDecoder()
                        decoder.dateDecodingStrategy = .iso8601
                        let order = try decoder.decode(TradeOrder.self, from: data)
                        
                        self?.tradingQueue.async {
                            self?.activeOrders.append(order)
                            self?.dailyTradeCount += 1
                            self?.lastTradeDate = Date()
                        }
                        
                        // Log trade for audit
                        AuditLogger.shared.logTrade(order: order)
                        
                        DispatchQueue.main.async {
                            completion(.success(order))
                        }
                    } catch {
                        DispatchQueue.main.async {
                            completion(.failure(.serverError("Failed to parse order response")))
                        }
                    }
                case .failure(let error):
                    DispatchQueue.main.async {
                        completion(.failure(.networkError(error.localizedDescription)))
                    }
                }
            }
        }
    }
    
    // MARK: - Order Management
    
    func cancelOrder(orderId: String, completion: @escaping (Result<TradeOrder, TradingError>) -> Void) {
        let integrity = integrityManager.performIntegrityCheck()
        guard integrity.overallTrust else {
            completion(.failure(.untrustedDevice))
            return
        }
        
        networkManager.authenticatedRequest(
            endpoint: "orders/\(orderId)/cancel",
            method: "POST"
        ) { [weak self] result in
            switch result {
            case .success(let data):
                do {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    let order = try decoder.decode(TradeOrder.self, from: data)
                    
                    self?.tradingQueue.async {
                        self?.activeOrders.removeAll { $0.id == orderId }
                        self?.orderHistory.append(order)
                    }
                    
                    DispatchQueue.main.async {
                        completion(.success(order))
                    }
                } catch {
                    DispatchQueue.main.async {
                        completion(.failure(.serverError("Failed to parse cancellation response")))
                    }
                }
            case .failure(let error):
                DispatchQueue.main.async {
                    completion(.failure(.networkError(error.localizedDescription)))
                }
            }
        }
    }
    
    func getActiveOrders(completion: @escaping (Result<[TradeOrder], Error>) -> Void) {
        networkManager.authenticatedRequest(endpoint: "orders?status=open") { result in
            switch result {
            case .success(let data):
                do {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    let orders = try decoder.decode([TradeOrder].self, from: data)
                    completion(.success(orders))
                } catch {
                    completion(.failure(SecureNetworkManager.NetworkError.decodingError))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getOrderHistory(completion: @escaping (Result<[TradeOrder], Error>) -> Void) {
        networkManager.authenticatedRequest(endpoint: "orders?status=closed") { result in
            switch result {
            case .success(let data):
                do {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    let orders = try decoder.decode([TradeOrder].self, from: data)
                    completion(.success(orders))
                } catch {
                    completion(.failure(SecureNetworkManager.NetworkError.decodingError))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    // MARK: - Validation
    
    private func validateOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Decimal,
        limitPrice: Decimal?,
        stopPrice: Decimal?
    ) -> Result<Void, TradingError> {
        // Basic validation
        guard !symbol.isEmpty else {
            return .failure(.invalidSymbol)
        }
        
        guard quantity > 0 else {
            return .failure(.invalidQuantity("Quantity must be greater than 0"))
        }
        
        // Check fractional shares support
        let fractionalPart = quantity - Decimal(Int(truncating: quantity as NSDecimalNumber))
        if fractionalPart != 0 && type != .market {
            return .failure(.invalidQuantity("Fractional shares only supported for market orders"))
        }
        
        // Validate limit price for limit orders
        if type == .limit || type == .stopLimit {
            guard let limitPrice = limitPrice, limitPrice > 0 else {
                return .failure(.invalidPrice("Limit price is required and must be positive"))
            }
        }
        
        // Validate stop price for stop orders
        if type == .stopLoss || type == .stopLimit {
            guard let stopPrice = stopPrice, stopPrice > 0 else {
                return .failure(.invalidPrice("Stop price is required and must be positive"))
            }
        }
        
        // Check daily trade limit
        if let lastDate = lastTradeDate, Calendar.current.isDateInToday(lastDate) {
            if dailyTradeCount >= maxDailyTrades {
                return .failure(.dailyLimitExceeded)
            }
        } else {
            dailyTradeCount = 0
        }
        
        // Check max order value
        let estimatedPrice = limitPrice ?? portfolio?.positions.first(where: { $0.symbol == symbol })?.currentPrice ?? 0
        let orderValue = quantity * estimatedPrice
        if orderValue > maxOrderValue {
            return .failure(.orderValueExceeded(maxOrderValue))
        }
        
        // Check selling quantity against position
        if side == .sell {
            portfolioLock.lock()
            let position = portfolio?.positions.first(where: { $0.symbol == symbol })
            portfolioLock.unlock()
            
            guard let pos = position, pos.quantity >= quantity else {
                return .failure(.insufficientShares)
            }
        }
        
        // Check buying power
        if side == .buy {
            portfolioLock.lock()
            let buyingPower = portfolio?.buyingPower ?? 0
            portfolioLock.unlock()
            
            if orderValue > buyingPower {
                return .failure(.insufficientFunds)
            }
        }
        
        return .success(())
    }
    
    private func generateIntegrityToken() -> String {
        let timestamp = Int(Date().timeIntervalSince1970)
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
        let payload = "\(timestamp):\(deviceId)"
        
        guard let data = payload.data(using: .utf8) else { return "" }
        let hash = SHA256.hash(data: data)
        return hash.compactMap { String(format: "%02x", $0) }.joined()
    }
    
    // MARK: - Trading Errors
    
    enum TradingError: Error, LocalizedError {
        case untrustedDevice
        case authenticationFailed
        case invalidSymbol
        case invalidQuantity(String)
        case invalidPrice(String)
        case insufficientFunds
        case insufficientShares
        case dailyLimitExceeded
        case orderValueExceeded(Decimal)
        case networkError(String)
        case serverError(String)
        case marketClosed
        case orderRejected(String)
        
        var errorDescription: String? {
            switch self {
            case .untrustedDevice:
                return "Trading is disabled on this device due to security concerns."
            case .authenticationFailed:
                return "Authentication failed. Please try again."
            case .invalidSymbol:
                return "Invalid stock symbol."
            case .invalidQuantity(let msg):
                return "Invalid quantity: \(msg)"
            case .invalidPrice(let msg):
                return "Invalid price: \(msg)"
            case .insufficientFunds:
                return "Insufficient buying power for this order."
            case .insufficientShares:
                return "Insufficient shares to sell."
            case .dailyLimitExceeded:
                return "Daily trade limit exceeded."
            case .orderValueExceeded(let max):
                return "Order value exceeds maximum of $\(max)."
            case .networkError(let msg):
                return "Network error: \(msg)"
            case .serverError(let msg):
                return "Server error: \(msg)"
            case .marketClosed:
                return "Market is currently closed."
            case .orderRejected(let reason):
                return "Order rejected: \(reason)"
            }
        }
    }
}

// MARK: - Real-Time Price WebSocket Manager

final class RealTimePriceManager: NSObject {
    static let shared = RealTimePriceManager()
    
    private var webSocketTask: URLSessionWebSocketTask?
    private var subscribedSymbols: Set<String> = []
    private var priceUpdateHandlers: [String: [(Decimal) -> Void]] = [:]
    private var isConnected = false
    private var reconnectAttempts = 0
    private let maxReconnectAttempts = 5
    private var pingTimer: Timer?
    
    private override init() {
        super.init()
    }
    
    func connect() {
        guard !isConnected else { return }
        
        let integrity = DeviceIntegrityManager.shared.performIntegrityCheck()
        guard integrity.overallTrust else {
            print("WebSocket connection blocked: untrusted device")
            return
        }
        
        guard let token = SecureStorageManager.shared.retrieveAPIToken(),
              let url = URL(string: "wss://stream.tradingplatform.com/v1/prices?token=\(token)") else {
            return
        }
        
        let session = URLSession(configuration: .default, delegate: SSLPinningDelegate(), delegateQueue: nil)
        webSocketTask = session.webSocketTask(with: url)
        webSocketTask?.resume()
        
        isConnected = true
        reconnectAttempts = 0
        
        receiveMessage()
        startPingTimer()
        
        // Resubscribe to symbols
        for symbol in subscribedSymbols {
            sendSubscription(symbol: symbol, action: "subscribe")
        }
    }
    
    func disconnect() {
        webSocketTask?.cancel(with: .goingAway, reason: nil)
        webSocketTask = nil
        isConnected = false
        pingTimer?.invalidate()
        pingTimer = nil
    }
    
    func subscribe(symbol: String, handler: @escaping (Decimal) -> Void) {
        subscribedSymbols.insert(symbol)
        
        if priceUpdateHandlers[symbol] == nil {
            priceUpdateHandlers[symbol] = []
        }
        priceUpdateHandlers[symbol]?.append(handler)
        
        if isConnected {
            sendSubscription(symbol: symbol, action: "subscribe")
        }
    }
    
    func unsubscribe(symbol: String) {
        subscribedSymbols.remove(symbol)
        priceUpdateHandlers.removeValue(forKey: symbol)
        
        if isConnected {
            sendSubscription(symbol: symbol, action: "unsubscribe")
        }
    }
    
    private func sendSubscription(symbol: String, action: String) {
        let message: [String: Any] = [
            "action": action,
            "symbol": symbol
        ]
        
        guard let data = try? JSONSerialization.data(withJSONObject: message),
              let jsonString = String(data: data, encoding: .utf8) else { return }
        
        webSocketTask?.send(.string(jsonString)) { error in
            if let error = error {
                print("WebSocket send error: \(error)")
            }
        }
    }
    
    private func receiveMessage() {
        webSocketTask?.receive { [weak self] result in
            switch result {
            case .success(let message):
                switch message {
                case .string(let text):
                    self?.handleMessage(text)
                case .data(let data):
                    if let text = String(data: data, encoding: .utf8) {
                        self?.handleMessage(text)
                    }
                @unknown default:
                    break
                }
                self?.receiveMessage()
                
            case .failure(let error):
                print("WebSocket receive error: \(error)")
                self?.handleDisconnection()
            }
        }
    }
    
    private func handleMessage(_ text: String) {
        guard let data = text.data(using: .utf8),
              let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
              let symbol = json["symbol"] as? String,
              let priceString = json["price"] as? String,
              let price = Decimal(string: priceString) else { return }
        
        DispatchQueue.main.async { [weak self] in
            self?.priceUpdateHandlers[symbol]?.forEach { handler in
                handler(price)
            }
        }
    }
    
    private func handleDisconnection() {
        isConnected = false
        pingTimer?.invalidate()
        
        guard reconnectAttempts < maxReconnectAttempts else {
            print("Max reconnection attempts reached")
            return
        }
        
        reconnectAttempts += 1
        let delay = Double(min(pow(2.0, Double(reconnectAttempts)), 30.0))
        
        DispatchQueue.main.asyncAfter(deadline: .now() + delay) { [weak self] in
            self?.connect()
        }
    }
    
    private func startPingTimer() {
        pingTimer?.invalidate()
        pingTimer = Timer.scheduledTimer(withTimeInterval: 30, repeats: true) { [weak self] _ in
            self?.webSocketTask?.sendPing { error in
                if let error = error {
                    print("Ping failed: \(error)")
                    self?.handleDisconnection()
                }
            }
        }
    }
}

// MARK: - Audit Logger

final class AuditLogger {
    static let shared = AuditLogger()
    
    private let logQueue = DispatchQueue(label: "com.tradingapp.audit", qos: .utility)
    
    private init() {}
    
    func logTrade(order: TradeOrder) {
        logQueue.async {
            let logEntry: [String: Any] = [
                "event": "trade_executed",
                "order_id": order.id,
                "symbol": order.symbol,
                "side": order.side.rawValue,
                "type": order.type.rawValue,
                "quantity": "\(order.quantity)",
                "status": order.status.rawValue,
                "timestamp": ISO8601DateFormatter().string(from: Date()),
                "device_id": UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
            ]
            
            // Send to audit endpoint
            SecureNetworkManager.shared.authenticatedRequest(
                endpoint: "audit/trades",
                method: "POST",
                body: logEntry
            ) { _ in }
        }
    }
    
    func logSecurityEvent(event: String, details: [String: Any] = [:]) {
        logQueue.async {
            var logEntry: [String: Any] = [
                "event": event,
                "timestamp": ISO8601DateFormatter().string(from: Date()),
                "device_id": UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
            ]
            logEntry.merge(details) { _, new in new }
            
            SecureNetworkManager.shared.authenticatedRequest(
                endpoint: "audit/security",
                method: "POST",
                body: logEntry
            ) { _ in }
        }
    }
}

// MARK: - Stock Search Service

final class StockSearchService {
    static let shared = StockSearchService()
    
    private let networkManager = SecureNetworkManager.shared
    private var searchCache: [String: [Stock]] = [:]
    
    private init() {}
    
    func searchStocks(query: String, completion: @escaping (Result<[Stock], Error>) -> Void) {
        let trimmedQuery = query.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard !trimmedQuery.isEmpty else {
            completion(.success([]))
            return
        }
        
        if let cached = searchCache[trimmedQuery] {
            completion(.success(cached))
            return
        }
        
        networkManager.authenticatedRequest(endpoint: "stocks/search?q=\(trimmedQuery)") { [weak self] result in
            switch result {
            case .success(let data):
                do {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    let stocks = try decoder.decode([Stock].self, from: data)
                    self?.searchCache[trimmedQuery] = stocks
                    completion(.success(stocks))
                } catch {
                    completion(.failure(SecureNetworkManager.NetworkError.decodingError))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
    
    func getStockQuote(symbol: String, completion: @escaping (Result<Stock, Error>) -> Void) {
        networkManager.authenticatedRequest(endpoint: "stocks/\(symbol)/quote") { result in
            switch result {
            case .success(let data):
                do {
                    let decoder = JSONDecoder()
                    decoder.dateDecodingStrategy = .iso8601
                    let stock = try decoder.decode(Stock.self, from: data)
                    completion(.success(stock))
                } catch {
                    completion(.failure(SecureNetworkManager.NetworkError.decodingError))
                }
            case .failure(let error):
                completion(.failure(error))
            }
        }
    }
}

// MARK: - UI Components

// Custom formatter for currency display
extension Decimal {
    var currencyFormatted: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = "USD"
        return formatter.string(from: self as NSDecimalNumber) ?? "$0.00"
    }
    
    var percentFormatted: String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .percent
        formatter.minimumFractionDigits = 2
        formatter.maximumFractionDigits = 2
        formatter.multiplier = 0.01
        return formatter.string(from: self as NSDecimalNumber) ?? "0.00%"
    }
}

// MARK: - Portfolio View Controller

final class PortfolioViewController: UIViewController {
    
    private let tradingEngine = TradingEngine.shared
    private let priceManager = RealTimePriceManager.shared
    
    private var portfolio: Portfolio?
    private var positions: [Position] = []
    
    private lazy var tableView: UITableView = {
        let tv = UITableView(frame: .zero, style: .grouped)
        tv.translatesAutoresizingMaskIntoConstraints = false
        tv.delegate = self
        tv.dataSource = self
        tv.register(PortfolioSummaryCell.self, forCellReuseIdentifier: "SummaryCell")
        tv.register(PositionCell.self, forCellReuseIdentifier: "PositionCell")
        tv.refreshControl = refreshControl
        return tv
    }()
    
    private lazy var refreshControl: UIRefreshControl = {
        let rc = UIRefreshControl()
        rc.addTarget(self, action: #selector(refreshPortfolio), for: .valueChanged)
        return rc
    }()
    
    private lazy var securityBanner: UIView = {
        let view = UIView()
        view.translatesAutoresizingMaskIntoConstraints = false
        view.backgroundColor = .systemRed
        view.isHidden = true
        
        let label = UILabel()
        label.translatesAutoresizingMaskIntoConstraints = false
        label.text = "⚠️ Device integrity compromised. Trading disabled."
        label.textColor = .white
        label.font = .systemFont(ofSize: 14, weight: .semibold)
        label.textAlignment = .center
        
        view.addSubview(label)
        NSLayoutConstraint.activate([
            label.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            label.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            label.leadingAnchor.constraint(greaterThanOrEqualTo: view.leadingAnchor, constant: 16),
            label.trailingAnchor.constraint(lessThanOrEqualTo: view.trailingAnchor, constant: -16)
        ])
        
        return view
    }()
    
    private var isTradingEnabled = true
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        title = "Portfolio"
        navigationController?.navigationBar.prefersLargeTitles = true
        
        setupUI()
        checkDeviceIntegrity()
        loadData()
    }
    
    override func viewWillAppear(_ animated: Bool) {
        super.viewWillAppear(animated)
        priceManager.connect()
    }
    
    override func viewWillDisappear(_ animated: Bool) {
        super.viewWillDisappear(animated)
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        
        view.addSubview(securityBanner)
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            securityBanner.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            securityBanner.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            securityBanner.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            securityBanner.heightAnchor.constraint(equalToConstant: 44),
            
            tableView.topAnchor.constraint(equalTo: securityBanner.bottomAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor)
        ])
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(
            image: UIImage(systemName: "plus.circle.fill"),
            style: .plain,
            target: self,
            action: #selector(showTradeScreen)
        )
    }
    
    private func checkDeviceIntegrity() {
        let integrity = DeviceIntegrityManager.shared.performIntegrityCheck()
        
        if !integrity.overallTrust {
            isTradingEnabled = false
            securityBanner.isHidden = false
            navigationItem.rightBarButtonItem?.isEnabled = false
            
            AuditLogger.shared.logSecurityEvent(event: "untrusted_device_detected", details: [
                "jailbroken": integrity.isJailbroken,
                "debugger": integrity.isDebuggerAttached,
                "emulator": integrity.isRunningInEmulator,
                "tampered": integrity.hasBeenTampered
            ])
        }
    }
    
    private func loadData() {
        tradingEngine.loadPortfolio { [weak self] result in
            DispatchQueue.main.async {
                self?.refreshControl.endRefreshing()
                
                switch result {
                case .success(let portfolio):
                    self?.portfolio = portfolio
                    self?.positions = portfolio.positions
                    self?.tableView.reloadData()
                    self?.subscribeToRealTimePrices()
                    
                case .failure(let error):
                    self?.showError(error)
                }
            }
        }
    }
    
    private func subscribeToRealTimePrices() {
        for position in positions {
            priceManager.subscribe(symbol: position.symbol) { [weak self] newPrice in
                guard let self = self,
                      let index = self.positions.firstIndex(where: { $0.symbol == position.symbol }) else { return }
                
                self.positions[index].currentPrice = newPrice
                self.positions[index].lastUpdated = Date()
                
                let indexPath = IndexPath(row: index, section: 1)
                if let cell = self.tableView.cellForRow(at: indexPath) as? PositionCell {
                    cell.updatePrice(newPrice, position: self.positions[index])
                }
            }
        }
    }
    
    @objc private func refreshPortfolio() {
        checkDeviceIntegrity()
        loadData()
    }
    
    @objc private func showTradeScreen() {
        guard isTradingEnabled else {
            showSecurityAlert()
            return
        }
        
        let tradeVC = TradeViewController()
        let navController = UINavigationController(rootViewController: tradeVC)
        present(navController, animated: true)
    }
    
    private func showError(_ error: Error) {
        let alert = UIAlertController(
            title: "Error",
            message: error.localizedDescription,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
    
    private func showSecurityAlert() {
        let alert = UIAlertController(
            title: "Trading Disabled",
            message: "Trading functionality is disabled because this device does not meet security requirements. Please use a trusted device.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - Portfolio TableView DataSource & Delegate

extension PortfolioViewController: UITableViewDataSource, UITableViewDelegate {
    
    func numberOfSections(in tableView: UITableView) -> Int {
        return 2
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        switch section {
        case 0: return 1
        case 1: return positions.count
        default: return 0
        }
    }
    
    func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        switch section {
        case 0: return "Account Summary"
        case 1: return "Positions (\(positions.count))"
        default: return nil
        }
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        switch indexPath.section {
        case 0:
            let cell = tableView.dequeueReusableCell(withIdentifier: "SummaryCell", for: indexPath) as! PortfolioSummaryCell
            if let portfolio = portfolio {
                cell.configure(with: portfolio)
            }
            return cell
            
        case 1:
            let cell = tableView.dequeueReusableCell(withIdentifier: "PositionCell", for: indexPath) as! PositionCell
            cell.configure(with: positions[indexPath.row])
            return cell
            
        default:
            return UITableViewCell()
        }
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        
        guard indexPath.section == 1 else { return }
        
        let position = positions[indexPath.row]
        let detailVC = PositionDetailViewController(position: position, tradingEnabled: isTradingEnabled)
        navigationController?.pushViewController(detailVC, animated: true)
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        switch indexPath.section {
        case 0: return 180
        case 1: return 80
        default: return 44
        }
    }
}

// MARK: - Portfolio Summary Cell

final class PortfolioSummaryCell: UITableViewCell {
    
    private let totalEquityLabel = UILabel()
